import { afterEach, beforeEach, describe, it } from "vitest";
import assert from "node:assert/strict";
import path from "node:path";

import { WorktreePool } from "../../src/server/agent/worktree-pool.ts";
import { createWorktree, createWorktreeSet } from "../../src/server/skills/git.ts";
import type { CommandRunner } from "../../src/server/gateway-deps.ts";
import { installMemoryFs } from "./helpers/memory-fs-spies.js";
import type { MemFs } from "../harness/mem-fs.js";

let memoryFs: MemFs;
let restoreFs: () => void;
let fixtureSequence = 0;

beforeEach(() => {
	({ fs: memoryFs, restore: restoreFs } = installMemoryFs());
});

afterEach(() => restoreFs());

interface FakeGitState {
	commands: string[];
	localBranches: Map<string, string>;
	remoteRefs: Map<string, string>;
	upstreams: Map<string, string>;
}

function fakeGitRunner(repoPath: string, initial?: { branch: string; upstream?: string }): {
	state: FakeGitState;
	runner: CommandRunner;
} {
	const state: FakeGitState = {
		commands: [],
		localBranches: new Map([["master", "sha:master"]]),
		remoteRefs: new Map([["refs/heads/master", "sha:master"]]),
		upstreams: new Map(),
	};
	if (initial) {
		state.localBranches.set(initial.branch, `sha:${initial.branch}`);
		if (initial.upstream) state.upstreams.set(initial.branch, initial.upstream);
	}
	const record = (args: readonly string[]) => state.commands.push(args.join(" "));

	const runner: CommandRunner = {
		execFileSync(file, args) {
			assert.equal(file, "git");
			record(args);
			if (args[0] === "rev-parse" && args[1] === "--show-toplevel") return repoPath;
			throw new Error(`unexpected synchronous git command: ${args.join(" ")}`);
		},
		async execFile(file, args) {
			assert.equal(file, "git");
			record(args);

			if (args[0] === "rev-parse" && args[1] === "--verify") {
				const branch = String(args[2]).replace(/^refs\/heads\//, "");
				const sha = state.localBranches.get(branch);
				if (!sha) throw new Error(`missing ref: ${args[2]}`);
				return { stdout: `${sha}\n`, stderr: "" };
			}
			if (args[0] === "worktree" && args[1] === "add" && args[2] === "-b") {
				const branch = String(args[3]);
				state.localBranches.set(branch, `sha:${branch}`);
			}
			if (args[0] === "branch" && args[1] === "-m") {
				const oldBranch = String(args[2]);
				const newBranch = String(args[3]);
				state.localBranches.set(newBranch, state.localBranches.get(oldBranch) ?? `sha:${newBranch}`);
				state.localBranches.delete(oldBranch);
				const inherited = state.upstreams.get(oldBranch);
				state.upstreams.delete(oldBranch);
				if (inherited) state.upstreams.set(newBranch, inherited);
			}
			if (args[0] === "branch" && args[1] === "--unset-upstream") {
				state.upstreams.delete(String(args[2]));
			}
			if (args[0] === "branch" && String(args[1]).startsWith("--set-upstream-to=")) {
				state.upstreams.set(String(args[2]), String(args[1]).slice("--set-upstream-to=".length));
			}
			if (args[0] === "for-each-ref") {
				const branch = String(args.at(-1)).replace(/^refs\/heads\//, "");
				return { stdout: state.upstreams.get(branch) ? `${state.upstreams.get(branch)}\n` : "", stderr: "" };
			}
			if (args[0] === "push" && args[1] === "origin") {
				const [source, destination] = String(args[2]).split(":", 2);
				assert.ok(source && destination, `push must use an explicit destination refspec: ${args.join(" ")}`);
				state.remoteRefs.set(destination, state.localBranches.get(source) ?? `sha:${source}`);
			}
			if (args[0] === "symbolic-ref") {
				return { stdout: "refs/remotes/origin/master\n", stderr: "" };
			}
			return { stdout: "", stderr: "" };
		},
	};
	return { state, runner };
}

async function withFakeRepo<T>(fn: (root: string, repo: string) => Promise<T>): Promise<T> {
	const root = path.resolve("/memfs/local-push-policy", String(fixtureSequence++));
	const repo = path.join(root, "repo");
	memoryFs.mkdirSync(repo, { recursive: true });
	return fn(root, repo);
}

function assertNoPush(commands: string[], message: string): void {
	assert.ok(!commands.some((command) => command.startsWith("push ")), `${message}; commands:\n${commands.join("\n")}`);
}

describe("host worktree push policy", () => {
	it("createWorktree local-only skips push, origin branch fetch, and origin branch upstream", async () => {
		await withFakeRepo(async (_root, repo) => {
			const branch = "session/local-only";
			const { state, runner } = fakeGitRunner(repo);
			const result = await createWorktree(repo, branch, {
				startPoint: "origin/master",
				pushPolicy: "local-only",
				commandRunner: runner,
			});

			assert.equal(result.branchName, branch);
			assertNoPush(state.commands, "local-only must not run git push");
			assert.ok(!state.commands.includes(`fetch origin refs/heads/${branch}:refs/remotes/origin/${branch}`));
			assert.ok(!state.commands.includes(`branch --set-upstream-to=origin/${branch} ${branch}`));
			assert.equal(state.remoteRefs.has(`refs/heads/${branch}`), false);
			assert.equal(state.upstreams.has(branch), false);
		});
	});

	it("createWorktree defaults to publish with a safe destination refspec", async () => {
		await withFakeRepo(async (_root, repo) => {
			const branch = "session/publish-default";
			const masterRef = "refs/heads/master";
			const branchRef = `refs/heads/${branch}`;
			const { state, runner } = fakeGitRunner(repo);
			const masterBefore = state.remoteRefs.get(masterRef);

			await createWorktree(repo, branch, {
				startPoint: "origin/master",
				commandRunner: runner,
			});

			assert.ok(state.commands.includes(`push origin ${branch}:${branchRef}`), `publish must use explicit destination refspec; commands:\n${state.commands.join("\n")}`);
			assert.equal(state.remoteRefs.get(branchRef), `sha:${branch}`);
			assert.equal(state.remoteRefs.get(masterRef), masterBefore, "publishing a worktree branch must not target origin/master");
			assert.equal(state.upstreams.get(branch), `origin/${branch}`);
		});
	});

	it("BOBBIT_TEST_NO_PUSH suppresses publish even when pushPolicy is publish", async () => {
		await withFakeRepo(async (_root, repo) => {
			const branch = "session/no-push-policy";
			const { state, runner } = fakeGitRunner(repo);
			await createWorktree(repo, branch, {
				startPoint: "origin/master",
				pushPolicy: "publish",
				remotePolicy: { skipRemotePush: true },
				commandRunner: runner,
			});

			assertNoPush(state.commands, "no-push policy must suppress git push");
			assert.equal(state.remoteRefs.has(`refs/heads/${branch}`), false);
			assert.equal(state.upstreams.has(branch), false);
		});
	});

	it("worktree pool claim freshens without publishing the claimed branch", async () => {
		await withFakeRepo(async (root, repo) => {
			const poolBranch = "pool/_pool-local-only-policy";
			const targetBranch = "session/pool-local-only";
			const poolWorktree = path.join(root, "repo-wt", "pool-_pool-local-only-policy");
			const { state, runner } = fakeGitRunner(repo, { branch: poolBranch, upstream: "origin/master" });
			const pool = new WorktreePool({ repoPath: repo, targetSize: 0, commandRunner: runner });
			pool.registerExternalEntry(poolBranch, poolWorktree);
			try {
				const claim = await pool.claim(targetBranch);
				assert.ok(claim, "pool claim should succeed");
				await pool.stop();

				assertNoPush(state.commands, "pool claim/freshen must not run git push");
				assert.equal(state.remoteRefs.has(`refs/heads/${targetBranch}`), false);
				assert.equal(state.upstreams.has(targetBranch), false);
				assert.ok(state.commands.includes(`branch --unset-upstream ${targetBranch}`));
				assert.ok(!state.commands.includes(`branch --set-upstream-to=origin/${targetBranch} ${targetBranch}`));
			} finally {
				await pool.stop();
			}
		});
	});

	it("createWorktreeSet passes through publish policy and skipPush remains local-only", async () => {
		await withFakeRepo(async (_root, repo) => {
			const components = [{ name: "app", repo: "." }];
			const publishBranch = "set/publish";
			const publish = fakeGitRunner(repo);
			await createWorktreeSet(repo, components, publishBranch, "origin/master", {
				pushPolicy: "publish",
				commandRunner: publish.runner,
			});
			assert.ok(
				publish.state.commands.includes(`push origin ${publishBranch}:refs/heads/${publishBranch}`),
				`createWorktreeSet publish policy must reach createWorktree; commands:\n${publish.state.commands.join("\n")}`,
			);
			assert.equal(publish.state.remoteRefs.has(`refs/heads/${publishBranch}`), true);

			const skipBranch = "set/skip-push";
			const skipped = fakeGitRunner(repo);
			await createWorktreeSet(repo, components, skipBranch, "origin/master", {
				pushPolicy: "publish",
				skipPush: true,
				commandRunner: skipped.runner,
			});
			assertNoPush(skipped.state.commands, "skipPush must suppress git push");
			assert.equal(skipped.state.remoteRefs.has(`refs/heads/${skipBranch}`), false);
		});
	});
});
